@app.route("/items", methods=["GET"])
def list_items():
    api_cache_key = make_cache_key("api:items:list", {"args": dict(request.args)})
    cached_response = cache_get(api_cache_key)
    if cached_response is not None:
        return jsonify({"source": "api-cache", "data": cached_response})

