@app.route("/items", methods=["POST"])
def create_item():
    payload = request.get_json(silent=True) or {}
    name = payload.get("name")
    value = payload.get("value")

    if not name or not value:
        return jsonify({"error": "Both 'name' and 'value' are required"}), 400

    now = int(time.time())
    with closing(get_db_connection()) as conn:
        cursor = conn.execute(
            "INSERT INTO items (name, value, updated_at) VALUES (?, ?, ?)",
            (name, value, now),
        )
        conn.commit()
        item_id = cursor.lastrowid

    invalidate_item_caches()
    item, _ = fetch_item_by_id(item_id)
    return jsonify({"message": "Item created", "data": item}), 201


@app.route("/items/<int:item_id>", methods=["PUT"])
def update_item(item_id):
    payload = request.get_json(silent=True) or {}
    name = payload.get("name")
    value = payload.get("value")

    if not name or not value:
        return jsonify({"error": "Both 'name' and 'value' are required"}), 400

    now = int(time.time())
    with closing(get_db_connection()) as conn:
        cursor = conn.execute(
            "UPDATE items SET name = ?, value = ?, updated_at = ? WHERE id = ?",
            (name, value, now, item_id),
        )
        conn.commit()

        if cursor.rowcount == 0:
            return jsonify({"error": "Item not found"}), 404

    invalidate_item_caches(item_id)
    item, _ = fetch_item_by_id(item_id)
    return jsonify({"message": "Item updated", "data": item})


@app.route("/items/<int:item_id>", methods=["DELETE"])
def delete_item(item_id):
    with closing(get_db_connection()) as conn:
        cursor = conn.execute("DELETE FROM items WHERE id = ?", (item_id,))
        conn.commit()

        if cursor.rowcount == 0:
            return jsonify({"error": "Item not found"}), 404

    invalidate_item_caches(item_id)
    return jsonify({"message": "Item deleted"})


